import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Login from './components/Login';
import SearchBuses from './components/SearchBuses';
import BusList from './components/BusList';
import SeatSelection from './components/SeatSelection';
import BookingConfirmation from './components/BookingConfirmation';
import UserDashboard from './components/User/UserDashboard';
import BookingHistory from './components/User/BookingHistory';
import BusTracking from './components/User/BusTracking';
import BusManagerDashboard from './components/BusManager/BusManagerDashboard';
import AddBus from './components/BusManager/AddBus';
import AdminDashboard from './components/Admin/AdminDashboard';
import Payment from './components/Payment';

function App() {
  return (
    <Router>
      <div className="App">
        <nav className="navbar">
          <div className="container">
            <h1>Bus Booking System</h1>
            <div>
              <a href="/login">Login</a>
              <a href="/search">Search</a>
            </div>
          </div>
        </nav>
        
        <div className="container">
          <Routes>
            <Route path="/login" element={<Login />} />
            <Route path="/search" element={<SearchBuses />} />
            <Route path="/buses" element={<BusList />} />
            <Route path="/seats" element={<SeatSelection />} />
            <Route path="/payment" element={<Payment />} />
            <Route path="/confirmation" element={<BookingConfirmation />} />
            <Route path="/user-dashboard" element={<UserDashboard />} />
            <Route path="/booking-history" element={<BookingHistory />} />
            <Route path="/track-bus" element={<BusTracking />} />
            <Route path="/bus-manager-dashboard" element={<BusManagerDashboard />} />
            <Route path="/bus-manager/add-bus" element={<AddBus />} />
            <Route path="/admin-dashboard" element={<AdminDashboard />} />
            <Route path="/" element={<Navigate to="/login" />} />
          </Routes>
        </div>
      </div>
    </Router>
  );
}

export default App;
